select distinct
  "tag"."id",
  "tag"."value"
from
  "tag"
  inner join "tag_asset" on "tag"."id" = "tag_asset"."tagId"
where
  "tag_asset"."assetId" in (
    select
      "asset"."id"
    from
      "asset"
    where
      "asset"."visibility" = $1
      and "asset"."deletedAt" is null
      and (
        "asset"."ownerId" = any ($2::uuid[])
        or exists (
          select
          from
            "shared_space_asset"
          where
            "shared_space_asset"."assetId" = "asset"."id"
            and "shared_space_asset"."spaceId" = any ($3::uuid[])
        )
        or exists (
